import { useEffect, useState } from "react";
import API from "../api";
import Seat from "../components/seat";

export default function Reservation() {
	const [seats, setSeats] = useState([]);
	const [selected, setSelected] = useState(null);
	const [form, setForm] = useState({
		name: "",
		age: "",
		gender: "",
	});

	const fetchSeats = async () => {
		const open = await API.get("/tickets/open/all");
		const closed = await API.get("/tickets/closed/all");
		setSeats([...open.data, ...closed.data]);
	};

	useEffect(() => {
		fetchSeats();
	}, []);

	const bookSeat = async () => {
		await API.post(`/tickets/book/${selected}`, form);
		alert("Booked!");
		setSelected(null);
		fetchSeats();
	};

	return (
		<div>
			<h2>Reservation</h2>

			<div>
				{seats.map((s) => (
					<Seat key={s.seatNumber} seat={s} onClick={setSelected} />
				))}
			</div>

			{selected && (
				<div>
					<h3>Booking Seat {selected}</h3>
					<input
						placeholder="Name"
						onChange={(e) => setForm({ ...form, name: e.target.value })}
					/>
					<input
						placeholder="Age"
						onChange={(e) => setForm({ ...form, age: e.target.value })}
					/>
					<input
						placeholder="Gender"
						onChange={(e) => setForm({ ...form, gender: e.target.value })}
					/>
					<button onClick={bookSeat}>Confirm</button>
				</div>
			)}
		</div>
	);
}
